insert into idempotency_keys (idempotency_key, user_id,
request_hash, reference_id, status,
error_code, response_snapshot, created_at,
updated_at, retry_count, locked_until
)
values (#{idempotencyKey,jdbcType=VARCHAR}, #{userId,jdbcType=BIGINT},
#{requestHash,jdbcType=VARCHAR}, #{referenceId,jdbcType=VARCHAR}, #{status,jdbcType=VARCHAR},
#{errorCode,jdbcType=VARCHAR}, #{responseSnapshot,jdbcType=VARCHAR}, #{createdAt,jdbcType=TIMESTAMP},
