mapper.select:
SELECT idempotency_key, user_id, request_hash, reference_id, status, error_code, response_snapshot, created_at, updated_at, retry_count, locked_until
FROM idempotency_keys WHERE request_hash = #{requestHash} AND user_id = #{userId}
ORDER BY created_at DESC LIMIT 1

mapper.update:
