status = #{status}, retry_count = #{retryCount}, locked_until = #{lockedUntil}, updated_at = NOW()
WHERE idempotency_key = #{idempotencyKey}

UPDATE idempotency_keys
SET reference_id = #{referenceId}
WHERE idempotency_key = #{idempotencyKey}

